package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserParseTest {

    private File mockFile;
    private Charset charset;
    private CSVFormat mockFormat;

    @BeforeEach
    void setUp() {
        mockFile = mock(File.class);
        charset = Charset.forName("UTF-8");
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void parse_ShouldThrowNullPointerException_WhenFileIsNull() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(null, charset, mockFormat);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void parse_ShouldThrowNullPointerException_WhenFormatIsNull() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockFile, charset, null);
        });
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void parse_ShouldReturnCSVParserInstance_WhenValidArguments() throws IOException {
        try (MockedConstruction<InputStreamReader> mockedInputStreamReader = Mockito.mockConstruction(InputStreamReader.class)) {
            try (MockedConstruction<FileInputStream> mockedFileInputStream = Mockito.mockConstruction(FileInputStream.class)) {
                CSVParser parser = CSVParser.parse(mockFile, charset, mockFormat);
                assertNotNull(parser);
                assertEquals(mockFormat, parser.format);
            }
        }
    }
}
